class Solution {
public:
    int minSwapsCouples(vector<int>& row) {
        int n = row.size() / 2;
        vector<int> couple(n);
        for (int i = 0; i < n; i++) {
            couple[i] = row[2 * i];
        }
        int res = 0;
        for (int i = 0; i < n; i++) {
            if (couple[i] != row[2 * i]) {
                int j = find(couple, i, row[2 * i]);
                swap(couple[i], couple[j]);
                res += abs(i - j);
            }
        }
        return res;
    }
    int find(vector<int>& couple, int i, int target) {
        while (couple[i] != target) {
            i = (i + 1) % couple.size();
        }
        return i;
    }
};
